import { install, update, getInstalledVersion } from 'hermesone';

// Install the latest Hermes One for the current OS/arch
await install();

// Later: update only if a newer release exists (no-op when up to date)
await update();

// Check what's installed (reads the app on disk, falls back to ~/.hermesone/state.json)
const current = await getInstalledVersion();
console.log(current ? `Hermes One ${current}` : 'Not installed');
